Usa la API de promesas de `fs`:

```javascript
const fs = require('fs').promises;

async function readData() {
  try {
    const data = await fs.readFile('data.json', 'utf8');
    const json = JSON.parse(data);
    console.log(json);
  } catch (err) {
    console.error('Error leyendo archivo:', err);
  }
}
readData();
```

