Se puede utilizar la función `crypto` para implementar un sistema de cifrado y descifrado. Por ejemplo: ```go
           package main

           import (
               "crypto/aes"
               "crypto/cipher"
               "crypto/rand"
               "encoding/base64"
               "errors"
               "fmt"
               "io"
           )

           func cifrar(mensaje string) (string, error) {
               clave := []byte("mi_clave_secreta")
               block, err := aes.NewCipher(clave)
               if err != nil {
                   return "", err
               }

               // Crear un vector de inicialización aleatorio
               iv := make([]byte, block.BlockSize())
               if _, err := io.ReadFull(rand.Reader, iv); err != nil {
                   return "", err
               }

               // Crear un cifrador
               cipher := cipher.NewCFBEncrypter(block, iv)

               // Cifrar el mensaje
               mensajeCifrado := make([]byte, len(mensaje))
               cipher.XORKeyStream(mensajeCifrado, []byte(mensaje))

               // Codificar el mensaje cifrado en Base64
               return base64.StdEncoding.EncodeToString(append(iv, mensajeCifrado...)), nil
           }

           func descifrar(mensajeCifrado string) (string, error) {
               clave := []byte("mi_clave_secreta")
               block, err := aes.NewCipher(clave)
               if err != nil {
                   return "", err
               }

               // Decodificar el mensaje cifrado de Base64
               mensajeCifradoBytes, err := base64.StdEncoding.DecodeString(mensajeCifrado)
               if err != nil {
                   return "", err
               }

               // Extraer el vector de inicialización
               iv := mensajeCifradoBytes[:block.BlockSize()]
               mensajeCifradoBytes = mensajeCifradoBytes[block.BlockSize():]

               // Crear un descifrador
               cipher := cipher.NewCFBDecrypter(block, iv)

               // Descifrar el mensaje
               mensajeDescifrado := make([]byte, len(mensajeCifradoBytes))
               cipher.XORKeyStream(mensajeDescifrado, mensajeCifradoBytes)

               return string(mensajeDescifrado), nil
           }

           func main() {
               mensaje := "Hola, mundo!"
               mensajeCifrado, err := cifrar(mensaje)
               if err != nil {
                   fmt.Println(err)
                   return
               }

               mensajeDescifrado, err := descifrar(mensajeCifrado)
               if err != nil {
                   fmt.Println(err)
                   return
               }

               fmt.Println("Mensaje original:", mensaje)
               fmt.Println("Mensaje cifrado:", mensajeCifrado)
               fmt.Println("Mensaje descifrado:", mensajeDescifrado)
           }
           ```

